def tsp_dp(graph):
    n = len(graph)
    all_points_set = (1 << n) - 1

    # Memoization to store computed subproblems
    dp = [[float('inf')] * (1 << n) for _ in range(n)]

    # Base case: start from first city
    for i in range(n):
        dp[i][1 << i] = 0

    # Iterate through all possible subsets
    for subset in range(1, 1 << n):
        for curr in range(n):
            if subset & (1 << curr):
                for next_city in range(n):
                    if curr != next_city and subset & (1 << next_city):
                        dp[curr][subset] = min(
                            dp[curr][subset], 
                            dp[next_city][subset ^ (1 << curr)] + graph[next_city][curr]
                        )

    # Find minimum tour cost
    return min(dp[i][all_points_set] + graph[i][0] for i in range(1, n))
