class MemoryAllocator:
    def __init__(self, total_size):
        self.memory = [0] * total_size
        self.free_blocks = [(0, total_size)]

    def allocate(self, size):
        for i, (start, block_size) in enumerate(self.free_blocks):
            if block_size >= size:
                self.free_blocks.pop(i)
                if block_size > size:
                    self.free_blocks.append((start + size, block_size - size))
                return start
        return -1

    def free(self, start, size):
        self.free_blocks.append((start, size))
        self.free_blocks.sort(key=lambda x: x[0])

        # Merge adjacent free blocks
        merged = []
        for block in self.free_blocks:
            if not merged or block[0] > merged[-1][0] + merged[-1][1]:
                merged.append(block)
            else:
                last = merged.pop()
                merged.append((last[0], last[1] + block[1]))

