def parse_expression(expr):
    def tokenize(expr):
        tokens = []
        i = 0
        while i < len(expr):
            if expr[i].isdigit():
                num = ''
                while i < len(expr) and expr[i].isdigit():
                    num += expr[i]
                    i += 1
                tokens.append(int(num))
            elif expr[i] in '+-*/':
                tokens.append(expr[i])
                i += 1
            else:
                i += 1
        return tokens

    def evaluate(tokens):
        def precedence(op):
            return 1 if op in '+-' else 2 if op in '*/' else 0

        output = []
        operators = []
        for token in tokens:
            if isinstance(token, int):
                output.append(token)
            else:
                while operators and precedence(operators[-1]) >= precedence(token):
                    op = operators.pop()
                    b = output.pop()
                    a = output.pop()
                    output.append(eval(f'{a} {op} {b}'))
                operators.append(token)

        while operators:
            op = operators.pop()
            b = output.pop()
            a = output.pop()
            output.append(eval(f'{a} {op} {b}'))

        return output[0]

    return evaluate(tokenize(expr))
