import heapq
import time

class Scheduler:
    def __init__(self):
        self.ready = []
        self.sleeping = []

    def call_soon(self, coro):
        heapq.heappush(self.ready, coro)

    def call_later(self, delay, coro):
        deadline = time.time() + delay
        heapq.heappush(self.sleeping, (deadline, coro))

    def run(self):
        while self.ready or self.sleeping:
            while self.sleeping and self.sleeping[0][0] <= time.time():
                _, coro = heapq.heappop(self.sleeping)
                heapq.heappush(self.ready, coro)

            if self.ready:
                coro = heapq.heappop(self.ready)
                try:
                    next(coro)
                    heapq.heappush(self.ready, coro)
                except StopIteration:
                    pass
