import random

def genetic_algorithm(population_size=100, generations=50):
    def fitness(individual):
        return sum(individual)  # Example fitness function

    def crossover(parent1, parent2):
        split = random.randint(0, len(parent1)-1)
        return parent1[:split] + parent2[split:]

    def mutate(individual, mutation_rate=0.1):
        return [gene if random.random() > mutation_rate else 1-gene for gene in individual]

    population = [[random.randint(0,1) for _ in range(10)] for _ in range(population_size)]

    for _ in range(generations):
        population = sorted(population, key=fitness, reverse=True)
        next_generation = population[:population_size//2]

        while len(next_generation) < population_size:
            parent1, parent2 = random.sample(population[:population_size//2], 2)
            child = mutate(crossover(parent1, parent2))
            next_generation.append(child)

        population = next_generation

    return max(population, key=fitness)

