from datetime import datetime

def parse_cron(cron_expr):
    fields = cron_expr.split()
    if len(fields) != 5:
        raise ValueError("Invalid cron expression")

    patterns = {
        'minute': r'^(\*|[0-5]?\d)$',
        'hour': r'^(\*|[01]?\d|2[0-3])$',
        'day': r'^(\*|[0-3]?\d)$',
        'month': r'^(\*|[0-1]?\d)$',
        'weekday': r'^(\*|[0-6])$'
    }

    for i, (name, pattern) in enumerate(patterns.items()):
        if not re.match(pattern, fields[i]):
            raise ValueError(f"Invalid {name} field")

    def matches_cron(dt):
        return (
            (fields[0] == '*' or int(fields[0]) == dt.minute) and
            (fields[1] == '*' or int(fields[1]) == dt.hour) and
            (fields[2] == '*' or int(fields[2]) == dt.day) and
            (fields[3] == '*' or int(fields[3]) == dt.month) and
            (fields[4] == '*' or int(fields[4]) == dt.weekday())
        )

    return matches_cron
