def wrap_text(text, width):
    words = text.split()
    lines = []
    current_line = []
    current_width = 0

    for word in words:
        if current_width + len(word) + len(current_line) <= width:
            current_line.append(word)
            current_width += len(word)
        else:
            lines.append(' '.join(current_line))
            current_line = [word]
            current_width = len(word)

