        self.z2 = np.dot(self.a1, self.W2) + self.b2
        self.a2 = self.sigmoid(self.z2)
        return self.a2

    def backward(self, X, y, output, learning_rate=0.1):
        error = y - output
        d2 = error * self.sigmoid_derivative(output)
        error_h1 = np.dot(d2, self.W2.T)
        d1 = error_h1 * self.sigmoid_derivative(self.a1)

        self.W2 += learning_rate * np.dot(self.a1.T, d2)
        self.b2 += learning_rate * np.sum(d2, axis=0, keepdims=True)
        self.W1 += learning_rate * np.dot(X.T, d1)
        self.b1 += learning_rate * np.sum(d1, axis=0, keepdims=True)

    def train(self, X, y, epochs):
        for _ in range(epochs):
            output = self.forward(X)
            self.backward(X, y, output)
