class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word):
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end = True

    def autocomplete(self, prefix):
        node = self.root
        for char in prefix:
            if char not in node.children:
                return []
            node = node.children[char]

        suggestions = []
        self._dfs(node, prefix, suggestions)
        return suggestions

    def _dfs(self, node, current, suggestions):
        if node.is_end:
            suggestions.append(current)

        for char, child in node.children.items():
            self._dfs(child, current + char, suggestions)

trie = Trie()
trie.insert("apple")
trie.insert("app")
trie.insert("apricot")
print(trie.autocomplete("ap"))  # ['app', 'apple', 'apricot']
